-- Backfill histórico (2020-01-02 a 2026-07-03) de Azúcar refinada (ICE White
-- Sugar #5, Londres), exportado de Investing.com por el usuario. No existe
-- ticker gratuito confiable para este contrato (a diferencia del crudo No.11,
-- que sí se automatiza vía Yahoo Finance) — se siembra manualmente una vez y
-- de aquí en adelante se sigue cargando a mano igual que hasta ahora.
on conflict (label, observed_at) do update set
  value = excluded.value,
  value_numeric = excluded.value_numeric,
  unit = excluded.unit,
  source_name = excluded.source_name,
  source_url = excluded.source_url,
  status = excluded.status,
  featured = excluded.featured;
